const body = $json.body || $json;
const required = ['request_id', 'workflow_type', 'generated_by', 'client', 'brand', 'campaign', 'brief', 'options', 'report_draft_types', 'safety'];
const missing = required.filter((key) => body[key] === undefined || body[key] === null);
const safety = body.safety || {};
const safetyOk = body.workflow_type === 'report_draft'
  && body.owner_approval_required === true
  && body.generate_images === false
  && body.generate_videos === false
  && body.pull_live_analytics === false
  && body.use_unverified_metrics === false
  && safety.no_auto_post === true
  && safety.no_auto_ads === true
  && safety.no_live_connectors === true
  && safety.no_platform_launch === true
  && safety.no_image_generation === true
  && safety.no_video_generation === true
  && safety.no_live_analytics_pull === true
  && safety.no_unverified_metrics === true
  && safety.no_secrets === true
  && safety.owner_approval_required === true;
if (missing.length || !safetyOk) {
  return [{ json: {
    ok: false,
    request_id: body.request_id || null,
    error: {
      code: missing.length ? 'INVALID_CONTRACT' : 'REJECTED_BY_SAFETY',
      message: missing.length ? `Missing required fields: ${missing.join(', ')}` : 'Safety flags rejected this request (report draft is notes only — no live analytics is pulled, no unverified metrics are claimed, and no image or video generation).'
    },
    status: 'failed',
    owner_approval_required: true,
    safety
  }}];
}
return [{ json: body }];

const request = $json;
const channel = request.options?.channel || 'Facebook';
const goal = request.options?.goal || 'branding';
const brand = request.brand?.name || 'Brand';
const campaign = request.campaign?.name || 'Campaign';
const dataBasis = 'No live analytics were pulled. Any figures must be owner-provided; unverified metrics are not claimed.';
const specs = [
  { key: 'campaign_status_summary', title: 'Campaign Status Summary Draft',       focus: 'Status overview',      objective: 'Summarize campaign status from the brief & approvals (no live data pulled)' },
  { key: 'performance_insight',     title: 'Performance Insight Notes',           focus: 'Insight framing',      objective: 'Frame performance insight notes using only owner-provided figures (no metrics invented)' },
  { key: 'content_creative_review', title: 'Content & Creative Review Notes',     focus: 'Content & creative',   objective: 'Review content/creative items already in Core for the owner' },
  { key: 'risks_learnings_actions', title: 'Risks, Learnings & Next Actions',     focus: 'Risks & next actions', objective: 'Draft risks, learnings, and suggested next actions for owner review' },
  { key: 'report_handoff',          title: 'Owner / Client Report Handoff Draft', focus: 'Report handoff',       objective: 'Assemble an owner/client-ready report draft skeleton for manual review' }
];
const items = specs.map((spec) => ({
  key: spec.key,
  title: spec.title,
  focus: spec.focus,
  objective: spec.objective,
  period: 'Assumption: current campaign window (owner to set exact dates)',
  data_basis: dataBasis,
  summary_body: `Report draft notes for ${brand} - "${campaign}" on ${channel}. ${spec.objective}. No live analytics pulled.`,
  key_points: `Key draft points for ${brand} (${spec.focus}). Owner reviews and validates any figures.`,
  next_actions: spec.key === 'risks_learnings_actions' ? 'Draft next actions for owner review: confirm real figures, prioritize top creative, decide next test.' : 'Owner reviews this draft and supplies/validates any figures before it is shared.',
  generated_by: 'n8n-ai-provider',
  workflow_type: 'report_draft',
  content_type: 'report_draft',
  status: 'pending_approval',
  owner_approval_required: true
}));
return [{ json: {
  ok: true,
  request_id: request.request_id,
  workflow_type: 'report_draft',
  content_type: 'report_draft',
  generated_by: 'n8n-ai-provider',
  owner_approval_required: true,
  status: 'pending_approval',
  job: {
    external_execution_id: $execution.id,
    item_count: items.length
  },
  items,
  safety: request.safety
}}];
